import json
import os
from subprocess import call
from google.cloud import storage

def main(event, context):
    # Extract filename and conversion options from event metadata
    filename = event['name']
    conversion_options = event['conversionOptions']

    # Use subprocess.call() with event parameters to run convert command
    call(['convert', '-quality', '80', '-strip', filename, f'{filename}_converted'])

    # Upload converted image to Cloud Storage
    storage_client = storage.Client()
    bucket = storage_client.bucket(os.environ['BUCKET_NAME'])
    blob = bucket.blob(f'{filename}_converted')
    blob.upload_from_string(open(f'{filename}_converted', 'rb').read())

    # Delete original image from Cloud Storage
    blob = bucket.blob(filename)
    blob.delete()